class Solution:
    def intersectionSizeTwo(self, intervals):
        # brute over a bounded coordinate domain: greedily but verify by DP-free set cover on small ranges
        # independent approach: sort by end, keep explicit chosen-point set
        ivs = sorted(intervals, key=lambda x: (x[1], -x[0]))
        chosen = []
        for a, b in ivs:
            inside = [p for p in chosen if a <= p <= b]
            need = 2 - len(inside)
            if need <= 0:
                continue
            cand = list(range(b, a - 1, -1))
            for p in cand:
                if p not in chosen and need > 0:
                    chosen.append(p)
                    need -= 1
        return len(chosen)

