class Solution:
    def intersectionSizeTwo(self, intervals):
        ivs = sorted(intervals, key=lambda x: (x[1], -x[0]))
        a = b = -1
        count = 0
        for s, e in ivs:
            if s > b:
                count += 2
                a, b = e - 1, e
            elif s > a:
                count += 1
                a, b = b, e
        return count

