var intersectionSizeTwo = function(intervals) {
    const ivs = intervals.slice().sort((x, y) => x[1] - y[1] || y[0] - x[0]);
    let a = -1, b = -1, count = 0;
    for (const [s, e] of ivs) {
        if (s > b) {
            count += 2;
            a = e - 1;
            b = e;
        } else if (s > a) {
            count += 1;
            a = b;
            b = e;
        }
    }
    return count;
};
